// Constants.kt
object ApiConstants {
    const val BASE_URL_DEV = "https://api.example.com/dev/users"
    const val BASE_URL_STAGING = "https://api.example.com/staging/users"
    const val BASE_URL_PRODUCTION = "https://api.example.com/prod/users"
}

enum class Environment {
    DEVELOPMENT, STAGING, PRODUCTION
}

// ApiService.kt
interface ApiService {
    @GET("/")
    suspend fun getUserProfiles(): List<UserProfile>
}

// RetrofitClient.kt
class RetrofitClient(
    private val environment: Environment,
    private val authToken: String
) {
    private val retrofit by lazy {
        val client = OkHttpClient.Builder()
            .addInterceptor { chain ->
                val request = chain.request().newBuilder()
                    .header("Authorization", "Bearer $authToken")
                    .build()
                chain.proceed(request)
            }
            .build()

        Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    private fun getBaseUrl(environment: Environment): String {
        return when (environment) {
            Environment.DEVELOPMENT -> ApiConstants.BASE_URL_DEV
            Environment.STAGING -> ApiConstants.BASE_URL_STAGING
            Environment.PRODUCTION -> ApiConstants.BASE_URL_PRODUCTION
        }
    }

    val apiService by lazy { retrofit.create(ApiService::class.java) }
}

